    {
      "type": "save_waveform",
      "params": {
        "channel": "CH1",
        "file_path": "CH1_waveform.bin",
        "format": "binary"
      }
    },
    {
      "type": "save_waveform",
      "params": {
        "channel": "CH2",
        "file_path": "CH2_waveform.bin",
